# Generic fallback affirmation for beyond 6 weeks postpartum
GENERIC_POSTPARTUM_AFFIRMATION = "You are doing a wonderful job. Every day you show up for your baby with love and presence is a success."

def get_weekly_tip(week: int, is_postpartum: bool = False, postpartum_week: int = None):
    """Get the weekly tip based on pregnancy week or postpartum week."""
    if is_postpartum and postpartum_week:
        if postpartum_week > 6:
            return POSTPARTUM_TIPS.get(6, "")  # Fallback to week 6
        return POSTPARTUM_TIPS.get(postpartum_week, "")
    return WEEKLY_TIPS.get(week, "")

def get_weekly_affirmation(week: int, is_postpartum: bool = False, postpartum_week: int = None):
    """Get the weekly affirmation based on pregnancy week or postpartum week."""
    if is_postpartum and postpartum_week:
        if postpartum_week > 6:
            return GENERIC_POSTPARTUM_AFFIRMATION
        return POSTPARTUM_AFFIRMATIONS.get(postpartum_week, GENERIC_POSTPARTUM_AFFIRMATION)
    return WEEKLY_AFFIRMATIONS.get(week, "")
